	lim := NewLimiter(Config{Rate: 100, Window: time.Second}, clock)

	var wg sync.WaitGroup
	var allowed atomic.Int64

	// Fire 200 concurrent requests on the same key.
	for i := 0; i < 200; i++ {
		wg.Add(1)
		go func() {
			defer wg.Done()
			if lim.Allow("shared") {
				allowed.Add(1)
			}
		}()
	}
